import { useParams, useNavigate } from "react-router-dom";

function ElectionDashboard() {
  const { id } = useParams();
  const navigate = useNavigate();

  return (
    <div>
      <h2>Election Management</h2>

      <button
        onClick={() => navigate(`/ec/constituency/${id}/election/announce`)}
      >
        Announce Election (Candidate Applications)
      </button>

      <button
        onClick={() => navigate(`/ec/constituency/${id}/election/candidates`)}
      >
        Review Candidates
      </button>

      <button
        onClick={() => navigate(`/ec/constituency/${id}/election/schedule`)}
      >
        Announce Election Date
      </button>
    </div>
  );
}

export default ElectionDashboard;
